interface RetryOptions {
  attempts?: number;
  baseDelay?: number;
  maxDelay?: number;
  jitter?: boolean;
  signal?: AbortSignal;
  onRetry?: (info: { attempt: number; error: Error; nextDelay: number }) => void;
}

async function retry<T>(fn: (attempt: number) => Promise<T>, options: RetryOptions = {}): Promise<T> {
  const { attempts = 3, baseDelay = 1000, maxDelay = 30000, jitter = true, signal, onRetry } = options;
  let lastError: Error | undefined;

  for (let attempt = 0; attempt < attempts; attempt++) {
    if (signal?.aborted) throw new Error('Aborted');
    try {
      return await fn(attempt);
    } catch (err) {
      lastError = err as Error;
      if (attempt >= attempts - 1) break;
      let delay = Math.min(baseDelay * Math.pow(2, attempt), maxDelay);
      if (jitter) delay = delay * (0.5 + Math.random() * 0.5);
      onRetry?.({ attempt, error: lastError, nextDelay: delay });
      await new Promise<void>((resolve, reject) => {
        const timer = setTimeout(resolve, delay);
        signal?.addEventListener('abort', () => { clearTimeout(timer); reject(new Error('Aborted')); }, { once: true });
      });
    }
  }
  throw lastError!;
}

export { retry, RetryOptions };

