type Result<T, E = Error> = Ok<T, E> | Err<T, E>;

class Ok<T, E> {
  readonly _tag = 'Ok' as const;
  constructor(readonly value: T) {}
  isOk(): this is Ok<T, E> { return true; }
  isErr(): this is Err<T, E> { return false; }
  map<U>(fn: (value: T) => U): Result<U, E> { return ok(fn(this.value)); }
  flatMap<U>(fn: (value: T) => Result<U, E>): Result<U, E> { return fn(this.value); }
  unwrapOr(_fallback: T): T { return this.value; }
  match<U>(handlers: { ok: (v: T) => U; err: (e: E) => U }): U { return handlers.ok(this.value); }
}

class Err<T, E> {
  readonly _tag = 'Err' as const;
  constructor(readonly error: E) {}
  isOk(): this is Ok<T, E> { return false; }
  isErr(): this is Err<T, E> { return true; }
  map<U>(_fn: (value: T) => U): Result<U, E> { return err(this.error); }
  flatMap<U>(_fn: (value: T) => Result<U, E>): Result<U, E> { return err(this.error); }
  unwrapOr(fallback: T): T { return fallback; }
  match<U>(handlers: { ok: (v: T) => U; err: (e: E) => U }): U { return handlers.err(this.error); }
}

function ok<T, E = Error>(value: T): Result<T, E> { return new Ok(value); }
function err<T, E = Error>(error: E): Result<T, E> { return new Err(error); }

function tryCatch<T>(fn: () => T): Result<T, Error> {
  try { return ok(fn()); } catch (e) { return err(e instanceof Error ? e : new Error(String(e))); }
}

export { Result, Ok, Err, ok, err, tryCatch };

